const express = require('express');
const app = express();
const morgan = require('morgan');
const winston = require('winston');

const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'audit.log' }),
  ],
});

morgan.token('userData', (req, res) => {
  return `Username: ${req.query.username}, IP: ${req.ip}, CustomHeader: ${req.get('CustomHeader')}`;
});

app.use(morgan(':remote-addr :method :url :status :response-time ms - :userData'));

app.get('/', (req, res) => {
  logger.info('HTTP request logged', {userData: req.query.username, ip: req.ip, customHeader: req.get('CustomHeader')});
  res.send('Hello World!');
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});